{
  "query": "query { getPackageVersion(name: \"python\") { version repository homepage distribution { downloadUrl size } } }"
}

{
  "query": "query GetPackage($name: String!) { getPackage(name: $name) { name namespace private versions { version createdAt distribution { downloadUrl size } } } }",
  "variables": { "name": "wasmer/winterjs" }
}

{
  "query": "query { getInterfaceVersion(name: \"wasi\", version: \"latest\") { interface { name description } packageVersions { edges { node { version package { name } distribution { downloadUrl } } } } } }"
}

{
  "query": "query { viewer { username email namespaces { edges { node { name } } } } }"
}

{
  "query": "query GetDeployApp($owner: String!, $name: String!) { getDeployApp(owner: $owner, name: $name) { id name url activeVersion { id version url createdAt } } }",
  "variables": { "owner": "wasmer", "name": "my-app" }
}

{
  "query": "mutation PublishPackage($input: PublishPackageInput!) { publishPackage(input: $input) { success packageVersion { version package { name } } } }",
  "variables": { "input": { "name": "my-namespace/my-package", "version": "0.1.0", "manifest": {}, "file": "<signed-upload-url>" } }
}

{
  "query": "mutation DeployApp($input: DeployAppInput!) { deployApp(input: $input) { deployAppVersion { id url app { name } } } }",
  "variables": { "input": { "name": "my-app", "owner": "wasmer", "config": { "kind": "wasmer.io/App.v0", "name": "my-app", "package": "wasmer/winterjs" } } }
}
